-- SCRIPT PARA ELIMINAR Y CREAR LA TABLA ARTICULOS EN PRODUCCIÓN (AUTOCONTENIDO)
-- Generado para corregir problemas de alineación de IDs de la tabla Articulos en producción.

BEGIN TRY
    BEGIN TRAN;

    -- 1. Eliminar Foreign Keys temporariamente (si existen)
    IF EXISTS (SELECT * FROM sys.foreign_keys WHERE name = 'FK_ArticulosPermitidos_Articulo')
        ALTER TABLE dbo.PlanesMetrosArticulosPermitidos DROP CONSTRAINT FK_ArticulosPermitidos_Articulo;

    -- 2. Eliminar la tabla si existe
    IF OBJECT_ID('dbo.Articulos', 'U') IS NOT NULL
        DROP TABLE dbo.Articulos;

    -- 3. Crear la tabla Articulos con la estructura exacta
    CREATE TABLE dbo.Articulos (
        ProIdProducto INT IDENTITY(1,1) NOT NULL,
        CodArticulo CHAR(20) NOT NULL,
        IDProdReact SMALLINT NULL,
        SupFlia CHAR(8) NULL,
        Grupo CHAR(20) NULL,
        CodStock CHAR(20) NULL,
        Descripcion CHAR(100) NULL,
        Mostrar BIT NULL,
        anchoimprimible REAL NULL,
        LLEVAPAPEL BIT NULL,
        MonIdMoneda INT NULL,
        ProCodigoOdooProducto VARCHAR(50) NULL,
        UniIdUnidad INT NULL,
        borrar INT NULL,
        CONSTRAINT PK_Articulos PRIMARY KEY CLUSTERED (ProIdProducto)
    );

    -- 4. Habilitar la inserción de IDs explícitos
    SET IDENTITY_INSERT dbo.Articulos ON;

    -- 5. Insertar los datos

    SET IDENTITY_INSERT dbo.Articulos OFF;

    -- 6. Recrear Foreign Keys (si aplica)
    IF OBJECT_ID('dbo.PlanesMetrosArticulosPermitidos', 'U') IS NOT NULL
    BEGIN
        IF NOT EXISTS (SELECT * FROM sys.foreign_keys WHERE name = 'FK_ArticulosPermitidos_Articulo')
        BEGIN
            ALTER TABLE dbo.PlanesMetrosArticulosPermitidos 
            ADD CONSTRAINT FK_ArticulosPermitidos_Articulo 
            FOREIGN KEY (ProIdProducto) REFERENCES dbo.Articulos(ProIdProducto);
        END
    END

    COMMIT TRAN;
    PRINT '✅ Tabla Articulos recreada y poblada exitosamente.';
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRAN;
    IF (SELECT OBJECTPROPERTY(OBJECT_ID('dbo.Articulos'), 'TableHasIdentity')) = 1
    BEGIN
        SET IDENTITY_INSERT dbo.Articulos OFF;
    END
    PRINT '❌ ERROR al recrear tabla Articulos: ' + ERROR_MESSAGE();
END CATCH
GO
